'use client';
import { signIn } from 'next-auth/react';
import { useState } from 'react';
import { useRouter } from 'next/navigation';

export default function Login() {
    const router = useRouter();
    const [email, setEmail] = useState('admin@baaghentertainment.com');
    const [password, setPassword] = useState('Admin@123');
    const [error, setError] = useState('');

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        const res = await signIn('credentials', {
            redirect: false,
            email,
            password,
        });
        if (res?.error) {
            setError('Invalid email or password');
        } else {
            router.push('/admin/dashboard');
        }
    };

    return (
        <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: '80vh' }}>
            <div style={{ backgroundColor: 'var(--color-charcoal)', padding: '3rem', borderRadius: '8px', border: '1px solid var(--color-gold)', width: '100%', maxWidth: '400px' }}>
                <h2 style={{ textAlign: 'center', marginBottom: '2rem', color: 'var(--color-gold)' }}>ADMIN LOG IN</h2>
                {error && <p style={{ color: 'red', marginBottom: '1rem', textAlign: 'center' }}>{error}</p>}
                <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
                    <input
                        type="email"
                        placeholder="Admin Email"
                        value={email}
                        onChange={(e) => setEmail(e.target.value)}
                        style={{ padding: '12px', backgroundColor: 'var(--color-black)', border: '1px solid rgba(255,255,255,0.1)', color: 'white' }}
                        required
                    />
                    <input
                        type="password"
                        placeholder="Password"
                        value={password}
                        onChange={(e) => setPassword(e.target.value)}
                        style={{ padding: '12px', backgroundColor: 'var(--color-black)', border: '1px solid rgba(255,255,255,0.1)', color: 'white' }}
                        required
                    />
                    <button type="submit" className="btn-primary">Login to Dashboard</button>
                </form>
            </div>
        </div>
    );
}
